#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    static char s[1000005];
    while (T--) {
        scanf("%s", s);
        int freq[26] = {0};
        for (int i = 0; s[i]; ++i) freq[s[i] - 'a']++;
        int odd = 0;
        for (int i = 0; i < 26; ++i) if (freq[i] & 1) odd++;
        printf("%s\n", odd <= 1 ? "YES" : "NO");
    }
    return 0;
}

