const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = parseInt(input[idx++], 10);
let results = [];
for (let t = 0; t < T; ++t) {
  const s = input[idx++];
  const freq = new Array(26).fill(0);
  for (const ch of s) {
    freq[ch.charCodeAt(0) - 97]++;
  }
  let odd = 0;
  for (let i = 0; i < 26; ++i) if (freq[i] % 2 !== 0) odd++;
  results.push(odd <= 1 ? 'YES' : 'NO');
}
console.log(results.join('\n'));
